use base::{BaseConfig, Algorithm};
use crate::harness::{self, BenchResult, gen_floats, format_count};

// ---------------------------------------------------------------------------
// Sum Reduction Benchmark
//
// Compares Rust, Burn (NdArray), and Base (Cranelift JIT) for f32 sum.
//
// Algorithm CLIF IR is generated by Lean at build time (see lean/ directory).
// ---------------------------------------------------------------------------

type B = burn::backend::NdArray<f32>;

const REDUCTION_ALGORITHM: &[u8] =
    include_bytes!(concat!(env!("OUT_DIR"), "/reduction_algorithm.bin"));

fn load_algorithm() -> (BaseConfig, Algorithm) {
    bincode::deserialize(REDUCTION_ALGORITHM).expect("Failed to deserialize reduction algorithm")
}

fn rust_sum(data: &[f32]) -> f64 {
    data.iter().map(|&x| x as f64).sum()
}

fn burn_sum(data: &[f32]) -> f64 {
    use burn::tensor::{Tensor, TensorData};
    let n = data.len();
    let device = Default::default();
    let t = Tensor::<B, 1>::from_data(
        TensorData::new(data.to_vec(), [n]),
        &device,
    );
    t.sum().into_scalar() as f64
}

/// Build payload: raw f32 bytes. n is derived from data_len / 4.
fn build_payload(data: &[f32]) -> Vec<u8> {
    let mut payload = Vec::with_capacity(data.len() * 4);
    for &v in data {
        payload.extend_from_slice(&v.to_le_bytes());
    }
    payload
}

fn close_enough(a: f64, b: f64) -> bool {
    if a.is_nan() || b.is_nan() {
        return false;
    }
    let diff = (a - b).abs();
    let mag = a.abs().max(b.abs()).max(1.0);
    diff / mag < 0.01
}

pub fn run(iterations: usize) -> Vec<BenchResult> {
    let sizes: &[usize] = &[1_000_000, 10_000_000, 50_000_000, 100_000_000];
    let mut results = Vec::new();

    // JIT compile once
    let (config, alg) = load_algorithm();
    let mut base_instance = base::Base::new(config).expect("Base::new failed");

    for &n in sizes {
        let data = gen_floats(n, 42);
        let payload = build_payload(&data);

        // Raw Rust
        let rust_ms = harness::median_of(iterations, || {
            let start = std::time::Instant::now();
            std::hint::black_box(rust_sum(&data));
            start.elapsed().as_secs_f64() * 1000.0
        });

        // Burn (NdArray CPU)
        let burn_ms = {
            use burn::tensor::{Tensor, TensorData};
            let device = Default::default();
            let t = Tensor::<B, 1>::from_data(TensorData::new(data.to_vec(), [n]), &device);
            harness::median_of(iterations, || {
                let start = std::time::Instant::now();
                std::hint::black_box(t.clone().sum().into_scalar());
                start.elapsed().as_secs_f64() * 1000.0
            })
        };

        // Base (Cranelift JIT) — execute with payload, read result from out buffer
        let mut out_buf = [0u8; 8];

        // Warmup
        let _ = base_instance.execute_into(&alg, &payload, &mut out_buf);

        let base_ms = harness::median_of(iterations, || {
            let start = std::time::Instant::now();
            let _ = base_instance.execute_into(&alg, &payload, &mut out_buf);
            start.elapsed().as_secs_f64() * 1000.0
        });

        let base_result = f64::from_le_bytes(out_buf);
        let rust_check = rust_sum(&data);
        let burn_check = burn_sum(&data);
        let verified = Some(
            close_enough(rust_check, burn_check) && close_enough(rust_check, base_result),
        );

        results.push(BenchResult {
            name: format!("Sum ({})", format_count(n)),
            python_ms: Some(burn_ms),
            rust_ms: Some(rust_ms),
            base_ms,
            verified,
        });
    }

    results
}
